1998 void VPHistogramRecipe::execute(VPTransformState &State) {
1999   IRBuilderBase &Builder = State.Builder;
2000 
2001   Value *Address = State.get(getOperand(0));
2002   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
2003   VectorType *VTy = cast<VectorType>(Address->getType());
2004 
2005   // The histogram intrinsic requires a mask even if the recipe doesn't;
2006   // if the mask operand was omitted then all lanes should be executed and
2007   // we just need to synthesize an all-true mask.
2008   Value *Mask = nullptr;
2009   if (VPValue *VPMask = getMask())
2010     Mask = State.get(VPMask);
2011   else
2012     Mask =
2013         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
2014 
2015   // If this is a subtract, we want to invert the increment amount. We may
2016   // add a separate intrinsic in future, but for now we'll try this.
2017   if (Opcode == Instruction::Sub)
2018     IncAmt = Builder.CreateNeg(IncAmt);
2019   else
2020     assert(Opcode == Instruction::Add && "only add or sub supported for now");
2021 
2022   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
2023                                 {VTy, IncAmt->getType()},
2024                                 {Address, IncAmt, Mask});
2025 }
