1913 /// Compute the cost for the intrinsic \p ID with \p Operands, produced by \p R.
1914 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1915                                             ArrayRef<const VPValue *> Operands,
1916                                             const VPRecipeWithIRFlags &R,
1917                                             ElementCount VF,
1918                                             VPCostContext &Ctx) {
1919   // Some backends analyze intrinsic arguments to determine cost. Use the
1920   // underlying value for the operand if it has one. Otherwise try to use the
1921   // operand of the underlying call instruction, if there is one. Otherwise
1922   // clear Arguments.
1923   // TODO: Rework TTI interface to be independent of concrete IR values.
1924   SmallVector<const Value *> Arguments;
1925   for (const auto &[Idx, Op] : enumerate(Operands)) {
1926     auto *V = Op->getUnderlyingValue();
1927     if (!V) {
1928       if (auto *UI = dyn_cast_or_null<CallBase>(R.getUnderlyingValue())) {
1929         Arguments.push_back(UI->getArgOperand(Idx));
1930         continue;
1931       }
1932       Arguments.clear();
1933       break;
1934     }
1935     Arguments.push_back(V);
1936   }
1937 
1938   Type *ScalarRetTy = Ctx.Types.inferScalarType(&R);
1939   Type *RetTy = VF.isVector() ? toVectorizedTy(ScalarRetTy, VF) : ScalarRetTy;
1940   SmallVector<Type *> ParamTys;
1941   for (const VPValue *Op : Operands) {
1942     ParamTys.push_back(VF.isVector()
1943                            ? toVectorTy(Ctx.Types.inferScalarType(Op), VF)
1944                            : Ctx.Types.inferScalarType(Op));
1945   }
1946 
1947   // TODO: Rework TTI interface to avoid reliance on underlying IntrinsicInst.
1948   FastMathFlags FMF =
1949       R.hasFastMathFlags() ? R.getFastMathFlags() : FastMathFlags();
1950   IntrinsicCostAttributes CostAttrs(
1951       ID, RetTy, Arguments, ParamTys, FMF,
1952       dyn_cast_or_null<IntrinsicInst>(R.getUnderlyingValue()),
1953       InstructionCost::getInvalid(), &Ctx.TLI);
1954   return Ctx.TTI.getIntrinsicInstrCost(CostAttrs, Ctx.CostKind);
1955 }
