2027 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
2028                                                VPCostContext &Ctx) const {
2029   // FIXME: Take the gather and scatter into account as well. For now we're
2030   //        generating the same cost as the fallback path, but we'll likely
2031   //        need to create a new TTI method for determining the cost, including
2032   //        whether we can use base + vec-of-smaller-indices or just
2033   //        vec-of-pointers.
2034   assert(VF.isVector() && "Invalid VF for histogram cost");
2035   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
2036   VPValue *IncAmt = getOperand(1);
2037   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2038   VectorType *VTy = VectorType::get(IncTy, VF);
2039 
2040   // Assume that a non-constant update value (or a constant != 1) requires
2041   // a multiply, and add that into the cost.
2042   InstructionCost MulCost =
2043       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2044   if (auto *IncAmountIRV = dyn_cast<VPIRValue>(IncAmt)) {
2045     ConstantInt *CI = dyn_cast<ConstantInt>(IncAmountIRV->getValue());
2046 
2047     if (CI && CI->getZExtValue() == 1)
2048       MulCost = TTI::TCC_Free;
2049   }
2050 
2051   // Find the cost of the histogram operation itself.
2052   Type *PtrTy = VectorType::get(AddressTy, VF);
2053   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2054   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2055                               Type::getVoidTy(Ctx.LLVMCtx),
2056                               {PtrTy, IncTy, MaskTy});
2057 
2058   // Add the costs together with the add/sub operation.
2059   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2060          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2061 }
